20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	};
24	const PROCESSING_FEE = 5;
25	
26	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
27	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
28	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
29	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
30	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
31	
32	export const quote = (
33	  _customer: Customer,
34	  step: QuoteStep,
35	  _quoteIndex: number,
36	): QuoteResult => {
37	  const basePremium = step.items.reduce(
38	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
39	    0,
40	  );
41	  const withFirstInsurance =
42	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
43	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
44	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
45	  return { premium };
46	};
47	
